class Solution:
    def recoverMaxHeap(self, nums: list[int]) -> None:
        for i in range(len(nums) - 1, -1, -1):
            heapify(nums, i, len(nums) - 1)
    def heapify(self, nums, i, end):
        largest = i
        left = 2 * i + 1
        right = 2 * i + 2
        if left <= end and nums[left] > nums[largest]:
            largest = left
        if right <= end and nums[right] > nums[largest]:
            largest = right
        if largest != i:
            nums[i], nums[largest] = nums[largest], nums[i]
            self.heapify(nums, largest, end)

